21	async function connect() {
22	  const browser = await chromium.connectOverCDP(CDP_URL);
23	  const ctx = browser.contexts()[0];
24	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
25	  if (!page) throw new Error('未找到小满页面');
26	  const talkFrame = page.frames()[1];
27	  if (!talkFrame) throw new Error('未找到聊天 iframe');
28	  return { browser, page, talkFrame };
29	}
30	
31	async function main() {
32	  console.log('[deep-scrape v7] 连接小满...');
33	  const { page, talkFrame } = await connect();
34	
35	  // Step 1: 提取全量客户原始数据
36	  console.log('Step 1: 提取全量客户原始数据...');
37	  const allRaw = await talkFrame.evaluate(() => {
38	    const data = window.__conversationListFullData__;
39	    if (!data || !Array.isArray(data)) return [];
40	    return data
41	      .filter(item => {
42	        const name = item.contact?.name || '';
43	        return name && !/Assistant\s*Eva/i.test(name) && !/系统通知/.test(name) && name.length > 1;
44	      })
45	      .map(item => {
46	        const c = item.contact || {};
47	        return {
48	          name: c.name || item.name || '',
49	          accountId: c.accountId || item.accountId || '',
50	          accountIdEncrypt: c.accountIdEncrypt || item.accountIdEncrypt || '',
51	          chatToken: c.chatToken || item.chatToken || '',
52	          cid: item.cid || '',
53	          aliIdEncrypt: c.aliIdEncrypt || item.aliIdEncrypt || '',
54	          loginId: c.loginId || item.loginId || '',
55	        };
56	      });
57	  });
58	  console.log(`   ${allRaw.length} 个客户`);
59	
60	  function findRaw(name) {
61	    let r = allRaw.find(r => r.name === name);
62	    if (r) return r;
63	    r = allRaw.find(r => r.name.includes(name) || name.includes(r.name));
64	    return r;
65	  }
66	
67	  // Step 2: 读取 P0 + P1 客户列表
68	  console.log('Step 2: 读取 P0+P1 客户列表...');
69	  const files = readdirSync(DATA_DIR).filter(f => f.includes('全量客户分类'));
70	  files.sort().reverse();
71	  const latest = files[0];
72	  if (!latest) { console.log('未找到分类数据'); return; }
73	
